import React, { useState, useEffect, createContext, useContext, useRef } from 'react';
import { BrowserRouter, Routes, Route, Link, Navigate, useNavigate, useLocation } from 'react-router-dom';
import axios from 'axios';
import './App.css';
import DoctorPortal from './pages/DoctorPortal';
import PatientPortal from './pages/PatientPortal';
import Landing from './pages/Landing';

// API Config
const API_URL = 'http://localhost:5000/api';
const api = axios.create({ baseURL: API_URL });

api.interceptors.request.use(config => {
    const token = localStorage.getItem('token');
    if (token) config.headers.Authorization = `Bearer ${token}`;
    return config;
});

// ==================== Auth Context ====================
const AuthContext = createContext();
const useAuth = () => useContext(AuthContext);

const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const token = localStorage.getItem('token');
        if (token) {
            api.get('/auth/me')
                .then(res => setUser(res.data.user))
                .catch(() => localStorage.removeItem('token'))
                .finally(() => setLoading(false));
        } else {
            setLoading(false);
        }
    }, []);

    const login = async (email, password) => {
        const res = await api.post('/auth/login', { email, password });
        localStorage.setItem('token', res.data.token);
        setUser(res.data.user);
        return res.data.user;
    };

    const register = async (email, password, name, role) => {
        const res = await api.post('/auth/register', { email, password, name, role });
        localStorage.setItem('token', res.data.token);
        setUser(res.data.user);
        return res.data.user;
    };

    const logout = () => {
        localStorage.removeItem('token');
        setUser(null);
    };

    return (
        <AuthContext.Provider value={{ user, login, register, logout, loading }}>
            {children}
        </AuthContext.Provider>
    );
};

// ==================== Login Page ====================
const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const { login } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const loggedInUser = await login(email, password);
            if (loggedInUser.role === 'doctor') navigate('/doctor-portal');
            else navigate('/patient-portal');
        } catch (err) {
            setError(err.response?.data?.message || 'Login failed');
        }
    };

    return (
        <div className="auth-container">
            <div className="auth-card glass-panel">
                <div className="auth-header">
                    <div className="logo pulse-animation">🏥</div>
                    <h1 className="gradient-text">Disease Predictor</h1>
                    <p>AI-Powered Multi-Modal Health Analysis</p>
                </div>
                <form onSubmit={handleSubmit}>
                    {error && <div className="error">{error}</div>}
                    <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required />
                    <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required />
                    <button type="submit" className="btn-primary glow-btn">Access Portal</button>
                </form>
                <p className="auth-link">New to the platform? <Link to="/register">Create an account</Link></p>
            </div>
        </div>
    );
};

// ==================== Register Page ====================
const Register = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [name, setName] = useState('');
    const [error, setError] = useState('');
    const { register } = useAuth();
    const navigate = useNavigate();
    const location = useLocation();
    const queryRole = new URLSearchParams(location.search).get('role') || 'patient';

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const registeredUser = await register(email, password, name, queryRole);
            if (registeredUser.role === 'doctor') navigate('/doctor-portal');
            else navigate('/patient-portal');
        } catch (err) {
            setError(err.response?.data?.message || 'Registration failed');
        }
    };

    return (
        <div className="auth-container">
            <div className="auth-card glass-panel">
                <div className="auth-header">
                    <div className="logo pulse-animation">🏥</div>
                    <h1 className="gradient-text">Join the Future</h1>
                </div>
                <form onSubmit={handleSubmit}>
                    {error && <div className="error">{error}</div>}
                    <input type="text" placeholder="Full Name" value={name} onChange={(e) => setName(e.target.value)} required />
                    <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required />
                    <input type="password" placeholder="Password (min 6 chars)" value={password} onChange={(e) => setPassword(e.target.value)} required minLength={6} />
                    <button type="submit" className="btn-primary glow-btn">Register</button>
                </form>
                <p className="auth-link">Already a member? <Link to="/login">Sign in</Link></p>
            </div>
        </div>
    );
};

// ==================== Symptom Checker ====================
const SymptomChecker = () => {
    const [availableSymptoms, setAvailableSymptoms] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedSymptoms, setSelectedSymptoms] = useState([]);
    const [loading, setLoading] = useState(false);
    const [extracting, setExtracting] = useState(false);
    const [result, setResult] = useState(null);

    // Multimodal States
    const [activeTab, setActiveTab] = useState('text');
    const [textInput, setTextInput] = useState('');

    // Image State
    const [imageData, setImageData] = useState(null);
    const [imagePreview, setImagePreview] = useState(null);
    const [imageMime, setImageMime] = useState('');

    // Voice State
    const [isRecording, setIsRecording] = useState(false);
    const [audioData, setAudioData] = useState(null);
    const [audioMime, setAudioMime] = useState('');
    const mediaRecorderRef = useRef(null);
    const audioChunksRef = useRef([]);

    useEffect(() => {
        api.get('/symptoms').then(res => setAvailableSymptoms(res.data.symptoms || []));
    }, []);

    const filteredSymptoms = availableSymptoms.filter(s =>
        s.toLowerCase().includes(searchTerm.toLowerCase()) && !selectedSymptoms.includes(s)
    );

    const addSymptom = (symptom) => {
        if (!selectedSymptoms.includes(symptom)) {
            setSelectedSymptoms([...selectedSymptoms, symptom]);
            setSearchTerm('');
        }
    };

    const removeSymptom = (symptom) => {
        setSelectedSymptoms(selectedSymptoms.filter(s => s !== symptom));
    };

    // --- Media Handlers ---
    const handleImageUpload = (e) => {
        const file = e.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setImagePreview(reader.result);
                // Extract base64 without prefix
                const base64String = reader.result.replace(/^data:(.*,)?/, '');
                setImageData(base64String);
                setImageMime(file.type);
            };
            reader.readAsDataURL(file);
        }
    };

    const startRecording = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            mediaRecorderRef.current = new MediaRecorder(stream);
            mediaRecorderRef.current.ondataavailable = (event) => {
                if (event.data.size > 0) audioChunksRef.current.push(event.data);
            };
            mediaRecorderRef.current.onstop = () => {
                const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
                const reader = new FileReader();
                reader.onloadend = () => {
                    const base64String = reader.result.replace(/^data:(.*,)?/, '');
                    setAudioData(base64String);
                    setAudioMime('audio/webm');
                };
                reader.readAsDataURL(audioBlob);
                audioChunksRef.current = [];
            };
            audioChunksRef.current = [];
            mediaRecorderRef.current.start();
            setIsRecording(true);
        } catch (err) {
            alert('Microphone access denied or unavailable.');
        }
    };

    const stopRecording = () => {
        if (mediaRecorderRef.current && isRecording) {
            mediaRecorderRef.current.stop();
            setIsRecording(false);
            mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
        }
    };

    const handleExtractSymptoms = async () => {
        if (!textInput && !imageData && !audioData) {
            alert("Please provide some input (text, voice, or image) for AI to analyze.");
            return;
        }

        setExtracting(true);
        try {
            const payload = {};
            if (activeTab === 'text' && textInput) payload.text = textInput;
            if (activeTab === 'image' && imageData) {
                payload.image = imageData;
                payload.mime_type = imageMime;
                if (textInput) payload.text = textInput; // Allow optional text with image
            }
            if (activeTab === 'voice' && audioData) {
                payload.audio = audioData;
                payload.mime_type = audioMime;
            }

            const res = await api.post('/extract', payload);
            if (res.data.success && res.data.symptoms.length > 0) {
                const newSymptoms = res.data.symptoms.filter(s => !selectedSymptoms.includes(s));
                if (newSymptoms.length > 0) {
                    setSelectedSymptoms([...selectedSymptoms, ...newSymptoms]);
                } else {
                    alert('AI found symptoms that are already in your list!');
                }
                // clear after successful extraction
                setTextInput('');
                setImageData(null);
                setImagePreview(null);
                setAudioData(null);
            } else {
                alert(res.data.message || 'No valid symptoms found from the input.');
            }
        } catch (err) {
            alert(err.response?.data?.message || 'Multimodal extraction failed. Please ensure Gemini API Key is configured.');
        } finally {
            setExtracting(false);
        }
    };

    const handlePredict = async () => {
        if (selectedSymptoms.length === 0) {
            alert('Please add at least one symptom');
            return;
        }
        setLoading(true);
        try {
            const res = await api.post('/predict', { symptoms: selectedSymptoms });
            setResult(res.data);
        } catch (err) {
            alert(err.response?.data?.message || 'Prediction failed');
        } finally {
            setLoading(false);
        }
    };

    if (result) {
        return <ResultsDisplay result={result} onReset={() => { setResult(null); setSelectedSymptoms([]); }} />;
    }

    return (
        <div className="checker-container">
            <div className="split-view">
                {/* Multimodal Input Section */}
                <div className="card glass-panel mm-card">
                    <h2 className="gradient-text">✨ AI Symptom Extraction</h2>
                    <p className="subtitle">Describe how you feel, speak to us, or upload an image.</p>

                    <div className="mm-tabs">
                        <button className={activeTab === 'text' ? 'active' : ''} onClick={() => setActiveTab('text')}>📝 Text</button>
                        <button className={activeTab === 'voice' ? 'active' : ''} onClick={() => setActiveTab('voice')}>🎙️ Voice</button>
                        <button className={activeTab === 'image' ? 'active' : ''} onClick={() => setActiveTab('image')}>📸 Image</button>
                    </div>

                    <div className="mm-content">
                        {activeTab === 'text' && (
                            <textarea 
                                className="mm-textarea" 
                                placeholder="E.g., I have been feeling very itchy and noticing a red rash on my arms..."
                                value={textInput}
                                onChange={(e) => setTextInput(e.target.value)}
                            />
                        )}

                        {activeTab === 'voice' && (
                            <div className="mm-voice">
                                <div className={`mic-container ${isRecording ? 'recording' : ''}`}>
                                    <button 
                                        className={`mic-btn ${isRecording ? 'pulse' : ''}`}
                                        onClick={isRecording ? stopRecording : startRecording}
                                    >
                                        {isRecording ? '🛑 Stop' : '🎤 Start Recording'}
                                    </button>
                                </div>
                                {audioData && !isRecording && <div className="success-tag">✅ Audio recorded! Ready to analyze.</div>}
                            </div>
                        )}

                        {activeTab === 'image' && (
                            <div className="mm-image">
                                {!imagePreview ? (
                                    <div className="upload-zone">
                                        <input type="file" accept="image/*" onChange={handleImageUpload} id="file-upload" />
                                        <label htmlFor="file-upload" className="upload-label">
                                            📁 Drag & Drop or Click to Upload
                                        </label>
                                    </div>
                                ) : (
                                    <div className="image-preview">
                                        <img src={imagePreview} alt="Preview" />
                                        <button className="btn-secondary" onClick={() => { setImagePreview(null); setImageData(null); }}>Remove</button>
                                        <textarea 
                                            className="mm-textarea small-margin" 
                                            placeholder="Optional: Add context to the image..."
                                            value={textInput}
                                            onChange={(e) => setTextInput(e.target.value)}
                                        />
                                    </div>
                                )}
                            </div>
                        )}
                    </div>

                    <button 
                        className="btn-ai-extract"
                        onClick={handleExtractSymptoms}
                        disabled={extracting}
                    >
                        {extracting ? '⏳ AI Analyzing...' : '✨ Auto-Extract Symptoms'}
                    </button>
                </div>

                {/* Manual Check Section */}
                <div className="card glass-panel selected-card">
                    <h2>🎯 Verified Symptoms</h2>
                    <p className="subtitle">AI selected + Manually added symptoms</p>

                    <div className="search-box">
                        <input type="text" placeholder="🔎 Manual search symptoms..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                        {searchTerm && (
                            <div className="symptom-dropdown">
                                {filteredSymptoms.slice(0, 10).map(symptom => (
                                    <div key={symptom} className="symptom-option" onClick={() => addSymptom(symptom)}>
                                        {symptom.replace(/_/g, ' ')}
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    <div className="selected-symptoms">
                        <div className="chips">
                            {selectedSymptoms.length === 0 ? (
                                <p className="empty-state">No symptoms selected yet.</p>
                            ) : (
                                selectedSymptoms.map(symptom => (
                                    <div key={symptom} className="chip">
                                        {symptom.replace(/_/g, ' ')}
                                        <button onClick={() => removeSymptom(symptom)}>×</button>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>

                    <button className="btn-primary glow-btn predict-btn" onClick={handlePredict} disabled={loading || selectedSymptoms.length === 0}>
                        {loading ? '🔬 Processing...' : '🔬 Run Clinical Prediction'}
                    </button>
                </div>
            </div>
        </div>
    );
};

// ==================== Results Display ====================
const ResultsDisplay = ({ result, onReset }) => {
    const final = result.final_prediction;
    const rf = result.rf_prediction;
    const knn = result.knn_prediction;
    const info = result.disease_info;

    const getConfidenceColor = (level) => {
        switch (level) {
            case 'High': return '#10b981';
            case 'Medium': return '#f59e0b';
            case 'Low': return '#ef4444';
            default: return '#6b7280';
        }
    };

    return (
        <div className="results-container slide-up">
            <div className="result-card main-result glass-panel">
                <div className="result-header">
                    <div>
                        <p className="result-label">Clinical Diagnosis Hypothesis</p>
                        <h1 className="gradient-text">{final.disease}</h1>
                        <p className="model-used">Engine: {final.model_used}</p>
                    </div>
                    <div className="confidence-badge" style={{ backgroundColor: getConfidenceColor(final.confidence_level), opacity: 0.9 }}>
                        <div className="confidence-value">{final.confidence.toFixed(1)}%</div>
                        <div className="confidence-label">{final.confidence_level}</div>
                    </div>
                </div>
            </div>

            <div className="card glass-panel info-card">
                <h3>📋 Diagnosis Information</h3>
                <p className="description">{info.description}</p>
                <div className="divider"></div>
                <h4>🛡️ Recommended Precautions</h4>
                <ul className="precautions">
                    {info.precautions.map((prec, idx) => (
                        <li key={idx}><span className="check-icon">✓</span> {prec}</li>
                    ))}
                </ul>
            </div>

            <div className="model-comparison">
                <div className="card model-card glass-panel">
                    <h4>🌲 Random Forest <span className="acc">Acc: 100%</span></h4>
                    <p className="disease-name">{rf.disease}</p>
                    <p className="confidence" style={{color: '#10b981'}}>{rf.confidence.toFixed(1)}%</p>
                    <div className="top-predictions">
                        <small>Alternatives:</small>
                        {rf.top_5.slice(1, 4).map((p, idx) => (
                            <div key={idx} className="prediction-item">
                                <span>{p.disease}</span>
                                <span>{p.probability.toFixed(1)}%</span>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="card model-card glass-panel">
                    <h4>🎯 K-Nearest Neighbors <span className="acc">Acc: 98.5%</span></h4>
                    <p className="disease-name">{knn.disease}</p>
                    <p className="confidence" style={{color: '#10b981'}}>{knn.confidence.toFixed(1)}%</p>
                    <div className="top-predictions">
                        <small>Alternatives:</small>
                        {knn.top_5.slice(1, 4).map((p, idx) => (
                            <div key={idx} className="prediction-item">
                                <span>{p.disease}</span>
                                <span>{p.probability.toFixed(1)}%</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            <div className="action-buttons">
                <button className="btn-primary glow-btn" onClick={onReset}>New Diagnosis</button>
                <Link to="/history" className="btn-secondary">View Case History</Link>
            </div>

            <div className="disclaimer">
                <small>⚠️ <strong>Disclaimer:</strong> This AI tool is for research/demonstration purposes only. Please consult a doctor for a professional medical diagnosis.</small>
            </div>
        </div>
    );
};

// ==================== History Page ====================
const History = () => {
    const [history, setHistory] = useState([]);

    useEffect(() => {
        api.get('/history').then(res => setHistory(res.data.data || []));
    }, []);

    return (
        <div className="history-container slide-up">
            <div className="card glass-panel">
                <h2 className="gradient-text">📜 Case History</h2>
                {history.length === 0 ? (
                    <p className="empty-state">No cases recorded yet.</p>
                ) : (
                    <div className="history-list">
                        {history.map(item => (
                            <div key={item._id} className="history-item">
                                <div className="history-header">
                                    <h3>{item.predictedDisease}</h3>
                                    <span className="confidence-pill">{item.confidence.toFixed(1)}%</span>
                                </div>
                                <p className="timestamp">{new Date(item.timestamp).toLocaleString()}</p>
                                <div className="symptoms-list">
                                    {item.symptoms.slice(0, 5).map((s, idx) => (
                                        <span key={idx} className="symptom-tag">{s.replace(/_/g, ' ')}</span>
                                    ))}
                                    {item.symptoms.length > 5 && <span className="symptom-tag extra">+ {item.symptoms.length - 5}</span>}
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
};

// ==================== Navigation ====================
const Navigation = () => {
    const { user, logout } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    return (
        <nav className="navbar glass-panel-nav">
            <div className="nav-brand">
                <span className="logo">🏥</span>
                <span className="brand-name">Disease Predictor AI</span>
            </div>
            {user && (
                <div className="nav-links">
                    {user.role === 'doctor' ? (
                        <Link to="/doctor-portal" className="nav-link" style={{display: 'flex', alignItems: 'center', gap: '0.25rem'}}><span style={{color:'#3b82f6'}}>●</span> Doctor Portal</Link>
                    ) : (
                        <>
                            <Link to="/patient-portal" className="nav-link" style={{display: 'flex', alignItems: 'center', gap: '0.25rem'}}><span style={{color:'#10b981'}}>●</span> Home</Link>
                            <Link to="/symptoms" className="nav-link">Check Symptoms</Link>
                            <Link to="/history" className="nav-link">History</Link>
                        </>
                    )}
                    <div className="user-capsule">
                        <span className="user-icon">👤</span> {user.name}
                    </div>
                    <button onClick={handleLogout} className="btn-logout">Sign Out</button>
                </div>
            )}
        </nav>
    );
};

// ==================== Protected Route ====================
const ProtectedRoute = ({ children }) => {
    const { user, loading } = useAuth();
    if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
    return user ? children : <Navigate to="/login" />;
};

// ==================== Main App ====================
function App() {
    return (
        <AuthProvider>
            <BrowserRouter>
                <div className="app">
                    <div className="bg-aurora"></div>
                    <Navigation />
                    <div className="container main-container">
                        <Routes>
                            <Route path="/" element={<Landing />} />
                            <Route path="/login" element={<Login />} />
                            <Route path="/register" element={<Register />} />
                            <Route path="/symptoms" element={<ProtectedRoute><SymptomChecker /></ProtectedRoute>} />
                            <Route path="/history" element={<ProtectedRoute><History /></ProtectedRoute>} />
                            <Route path="/patient-portal" element={<ProtectedRoute><PatientPortal /></ProtectedRoute>} />
                            <Route path="/doctor-portal" element={<ProtectedRoute><DoctorPortal /></ProtectedRoute>} />
                        </Routes>
                    </div>
                </div>
            </BrowserRouter>
        </AuthProvider>
    );
}

export default App;
